package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.junit.jupiter.api.Test;

class OmniJoinEstimatorSortedWitnessTest {

	private static final long SEED = 0x51E7C0DEL;
	private static final byte ATTR_P = OmniAttributeRef.component(1);

	@Test
	void sortedWitnessFactoryCompactsAdjacentDuplicatesWithoutSorting() {
		long first = 1L;
		long duplicate = 1L;
		long unsignedAfterPositiveRange = Long.MIN_VALUE;

		OmniWitnessSet witnesses = OmniWitnessSet.fromSortedUnsigned(
				new long[] { first, duplicate, unsignedAfterPositiveRange },
				new double[] { 2.0d, 3.0d, 5.0d }, 3, 0.5d, 1.0d,
				OmniWitnessSet.FallbackReason.NONE, 1.0d);

		assertEquals(2, witnesses.retainedWitnessCount());
		assertEquals(first, witnesses.hashAt(0));
		assertEquals(5.0d, witnesses.weightAt(0), 0.0d);
		assertEquals(unsignedAfterPositiveRange, witnesses.hashAt(1));
		assertEquals(5.0d, witnesses.weightAt(1), 0.0d);
		assertEquals(20.0d, witnesses.estimatedRows(), 0.0d);
	}

	@Test
	void sortedWitnessFactoryRejectsUnsortedInput() {
		assertThrows(IllegalArgumentException.class, () -> OmniWitnessSet.fromSortedUnsigned(
				new long[] { Long.MIN_VALUE, 1L }, new double[] { 1.0d, 1.0d }, 2, 1.0d, 1.0d,
				OmniWitnessSet.FallbackReason.NONE, 1.0d));
	}

	@Test
	void exactMultiValueProbeMergesSortedPostingsAndSumsDuplicateWitnesses() {
		OmniJoinEstimator estimator = newEstimator();
		OmniJoinEstimator.Relation relation = estimator.relation(OmniRelation.STATEMENT);
		long valueA = OmniJoinEstimator.stableHash("A");
		long valueB = OmniJoinEstimator.stableHash("B");
		long shared = 11L;
		long first = 3L;
		long last = Long.MIN_VALUE;

		relation.updateStatic(ATTR_P, valueA, last, 7.0d);
		relation.updateStatic(ATTR_P, valueA, shared, 2.0d);
		relation.updateStatic(ATTR_P, valueB, first, 5.0d);
		relation.updateStatic(ATTR_P, valueB, shared, 3.0d);

		OmniWitnessSet witnesses = estimator.probeStatic(relation, ATTR_P,
				OmniJoinEstimator.Predicate.anyOfHashes(valueA, valueB));

		assertSortedUnsigned(witnesses);
		assertEquals(3, witnesses.retainedWitnessCount());
		assertEquals(first, witnesses.hashAt(0));
		assertEquals(5.0d, witnesses.weightAt(0), 0.0d);
		assertEquals(shared, witnesses.hashAt(1));
		assertEquals(5.0d, witnesses.weightAt(1), 0.0d);
		assertEquals(last, witnesses.hashAt(2));
		assertEquals(7.0d, witnesses.weightAt(2), 0.0d);
		assertEquals(17.0d, estimator.estimateRows(witnesses), 0.0d);
	}

	@Test
	void intersectionProducesSortedWitnessesWithoutChangingWeightedRows() {
		OmniJoinEstimator estimator = newEstimator();
		OmniWitnessSet left = OmniWitnessSet.fromSortedUnsigned(
				new long[] { 2L, 9L, Long.MIN_VALUE },
				new double[] { 5.0d, 7.0d, 11.0d }, 3, 1.0d, 1.0d,
				OmniWitnessSet.FallbackReason.NONE, 1.0d);
		OmniWitnessSet right = OmniWitnessSet.fromSortedUnsigned(
				new long[] { 1L, 9L, Long.MIN_VALUE },
				new double[] { 13.0d, 17.0d, 19.0d }, 3, 1.0d, 1.0d,
				OmniWitnessSet.FallbackReason.NONE, 1.0d);

		OmniWitnessSet intersection = estimator.intersect(List.of(left, right));

		assertSortedUnsigned(intersection);
		assertEquals(2, intersection.retainedWitnessCount());
		assertEquals(9L, intersection.hashAt(0));
		assertEquals(119.0d, intersection.weightAt(0), 0.0d);
		assertEquals(Long.MIN_VALUE, intersection.hashAt(1));
		assertEquals(209.0d, intersection.weightAt(1), 0.0d);
		assertEquals(328.0d, estimator.estimateRows(intersection), 0.0d);
	}

	@Test
	void exactDirectedJoinMergesSortedOutputPostings() {
		OmniJoinEstimator estimator = newEstimator();
		OmniJoinEstimator.Relation relation = estimator.relation(OmniRelation.EDGE_FORWARD);
		long predicate = OmniJoinEstimator.stableHash("knows");
		long sourceA = 3L;
		long sourceB = 11L;
		long sharedOutput = 5L;
		long lastOutput = Long.MIN_VALUE;
		relation.updatePredicate(predicate, sourceA, lastOutput, 7.0d);
		relation.updatePredicate(predicate, sourceA, sharedOutput, 2.0d);
		relation.updatePredicate(predicate, sourceB, sharedOutput, 3.0d);

		OmniWitnessSet input = OmniWitnessSet.fromSortedUnsigned(new long[] { sourceA, sourceB },
				new double[] { 2.0d, 3.0d }, 2, 1.0d, 1.0d,
				OmniWitnessSet.FallbackReason.NONE, 1.0d);

		OmniWitnessSet output = estimator.probeJoinPredicate(input, relation, predicate,
				OmniJoinEstimator.OutputIdentifier.RECORD);

		assertSortedUnsigned(output);
		assertEquals(2, output.retainedWitnessCount());
		assertEquals(sharedOutput, output.hashAt(0));
		assertEquals(13.0d, output.weightAt(0), 0.0d);
		assertEquals(lastOutput, output.hashAt(1));
		assertEquals(14.0d, output.weightAt(1), 0.0d);
		assertEquals(27.0d, estimator.estimateRows(output), 0.0d);
	}

	@Test
	void accumulatorBuildsSortedWitnessSetAndCombinesDuplicates() {
		OmniWitnessAccumulator accumulator = OmniWitnessAccumulator.unordered();

		accumulator.add(Long.MIN_VALUE, 7.0d);
		accumulator.add(3L, 2.0d);
		accumulator.add(3L, 5.0d);

		OmniWitnessSet witnesses = accumulator.toWitnessSet(0.5d, 0.75d,
				OmniWitnessSet.FallbackReason.NONE, 1.0d);

		assertSortedUnsigned(witnesses);
		assertEquals(2, witnesses.retainedWitnessCount());
		assertEquals(3L, witnesses.hashAt(0));
		assertEquals(7.0d, witnesses.weightAt(0), 0.0d);
		assertEquals(Long.MIN_VALUE, witnesses.hashAt(1));
		assertEquals(7.0d, witnesses.weightAt(1), 0.0d);
		assertEquals(28.0d, witnesses.estimatedRows(), 0.0d);
		assertEquals(0.75d, witnesses.confidence(), 0.0d);
	}

	@Test
	void unitWeightCopyKeepsWitnessMetadata() {
		OmniWitnessSet source = OmniWitnessSet.fromSortedUnsigned(new long[] { 2L, 9L },
				new double[] { 4.0d, 8.0d }, 2, 0.25d, 0.5d,
				OmniWitnessSet.FallbackReason.SAMPLE_LOSS, 16.0d);

		OmniWitnessSet unit = OmniWitnessAccumulator.unitWeights(source).toWitnessSet(source);

		assertEquals(2, unit.retainedWitnessCount());
		assertEquals(1.0d, unit.weightAt(0), 0.0d);
		assertEquals(1.0d, unit.weightAt(1), 0.0d);
		assertEquals(0.25d, unit.samplingProbability(), 0.0d);
		assertEquals(0.5d, unit.confidence(), 0.0d);
		assertEquals(OmniWitnessSet.FallbackReason.SAMPLE_LOSS, unit.fallbackReason());
		assertEquals(16.0d, unit.minimumDetectableRows(), 0.0d);
	}

	@Test
	void maxUnionUsesLargestWeightForSharedWitnesses() {
		OmniWitnessSet left = OmniWitnessSet.fromSortedUnsigned(new long[] { 2L, 9L },
				new double[] { 4.0d, 8.0d }, 2, 0.5d, 0.8d,
				OmniWitnessSet.FallbackReason.NONE, 1.0d);
		OmniWitnessSet right = OmniWitnessSet.fromSortedUnsigned(new long[] { 2L, Long.MIN_VALUE },
				new double[] { 7.0d, 11.0d }, 2, 0.25d, 0.6d,
				OmniWitnessSet.FallbackReason.SAMPLE_LOSS, 9.0d);

		OmniWitnessSet union = OmniWitnessAccumulator.maxUnion(List.of(left, right));

		assertSortedUnsigned(union);
		assertEquals(3, union.retainedWitnessCount());
		assertEquals(2L, union.hashAt(0));
		assertEquals(7.0d, union.weightAt(0), 0.0d);
		assertEquals(9L, union.hashAt(1));
		assertEquals(8.0d, union.weightAt(1), 0.0d);
		assertEquals(Long.MIN_VALUE, union.hashAt(2));
		assertEquals(11.0d, union.weightAt(2), 0.0d);
		assertEquals(0.25d, union.samplingProbability(), 0.0d);
		assertEquals(0.6d, union.confidence(), 0.0d);
		assertEquals(OmniWitnessSet.FallbackReason.SAMPLE_LOSS, union.fallbackReason());
		assertEquals(9.0d, union.minimumDetectableRows(), 0.0d);
	}

	@Test
	void subtractKeepsInputOrderAndConfidence() {
		OmniWitnessSet input = OmniWitnessSet.fromSortedUnsigned(new long[] { 2L, 9L, Long.MIN_VALUE },
				new double[] { 4.0d, 8.0d, 16.0d }, 3, 0.5d, 0.9d,
				OmniWitnessSet.FallbackReason.NONE, 1.0d);
		OmniWitnessSet removals = OmniWitnessSet.fromSortedUnsigned(new long[] { 9L },
				new double[] { 1.0d }, 1, 1.0d, 0.4d,
				OmniWitnessSet.FallbackReason.SAMPLE_LOSS, 7.0d);

		OmniWitnessSet remaining = OmniWitnessAccumulator.subtract(input, removals);

		assertSortedUnsigned(remaining);
		assertEquals(2, remaining.retainedWitnessCount());
		assertEquals(2L, remaining.hashAt(0));
		assertEquals(4.0d, remaining.weightAt(0), 0.0d);
		assertEquals(Long.MIN_VALUE, remaining.hashAt(1));
		assertEquals(16.0d, remaining.weightAt(1), 0.0d);
		assertEquals(0.4d, remaining.confidence(), 0.0d);
		assertEquals(OmniWitnessSet.FallbackReason.SAMPLE_LOSS, remaining.fallbackReason());
	}

	private static OmniJoinEstimator newEstimator() {
		return new OmniJoinEstimator(64, 4, 64, SEED);
	}

	private static void assertSortedUnsigned(OmniWitnessSet witnesses) {
		for (int i = 1; i < witnesses.retainedWitnessCount(); i++) {
			assertTrue(Long.compareUnsigned(witnesses.hashAt(i - 1), witnesses.hashAt(i)) < 0,
					"Witness hashes must be strictly sorted by unsigned hash");
		}
	}
}
